using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Services;

/// <summary>
/// Shared metadata populated during model training and consumed by the prediction endpoint.
/// </summary>
public class TicketModelMetadata
{
    public string ModelPath { get; set; } = string.Empty;
    public string[] Labels { get; set; } = [];
}

using Microsoft.ML;
using Microsoft.ML.Data;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

/// <summary>
/// Trains the ticket classification model at startup, logs evaluation metrics,
/// and saves the model for the PredictionEnginePool to load.
/// </summary>
public class ModelTrainerService : IHostedService
{
    private readonly ILogger<ModelTrainerService> _logger;
    private readonly TicketModelMetadata _metadata;
    private readonly string _dataPath;

    public ModelTrainerService(
        ILogger<ModelTrainerService> logger,
        TicketModelMetadata metadata,
        IWebHostEnvironment env)
    {
        _logger = logger;
        _metadata = metadata;
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
    }

    public Task StartAsync(CancellationToken cancellationToken)
    {
        var mlContext = new MLContext(seed: 42);

        var data = mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketInput.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate(
                "Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                "Label", "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training ticket classification model...");
        var model = pipeline.Fit(split.TrainSet);

        // Evaluate on held-out test set
        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);

        _logger.LogInformation("=== Model Evaluation Metrics ===");
        _logger.LogInformation("  MacroAccuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("  MicroAccuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
        _logger.LogInformation("  LogLoss:          {LogLoss:F4}", metrics.LogLoss);
        _logger.LogInformation("  LogLossReduction: {LogLossReduction:F4}", metrics.LogLossReduction);

        if (metrics.ConfusionMatrix is not null)
        {
            _logger.LogInformation("  Confusion Matrix:\n{Matrix}",
                metrics.ConfusionMatrix.GetFormattedConfusionTable());
        }

        // Extract label-to-score index mapping from the trained model
        var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
        predictions.Schema["Score"].GetSlotNames(ref labelBuffer);
        _metadata.Labels = labelBuffer.DenseValues().Select(v => v.ToString()).ToArray();

        _logger.LogInformation("  Labels: {Labels}", string.Join(", ", _metadata.Labels));

        mlContext.Model.Save(model, data.Schema, _metadata.ModelPath);
        _logger.LogInformation("Model saved to {ModelPath}", _metadata.ModelPath);

        return Task.CompletedTask;
    }

    public Task StopAsync(CancellationToken cancellationToken) => Task.CompletedTask;
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;
    private readonly TicketModelMetadata _metadata;

    public TicketsController(
        PredictionEnginePool<TicketInput, TicketPrediction> predictionPool,
        TicketModelMetadata metadata)
    {
        _predictionPool = predictionPool;
        _metadata = metadata;
    }

    [HttpPost("classify")]
    public IActionResult Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) || string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject and Description are required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var scores = _metadata.Labels
            .Zip(prediction.Score)
            .ToDictionary(pair => pair.First, pair => Math.Round(pair.Second, 4));

        return Ok(new
        {
            prediction.Category,
            Confidence = Math.Round(prediction.Score.Max(), 4),
            Scores = scores
        });
    }
}

public record TicketRequest(string Subject, string Description, int Priority);

