using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);

// Shared metadata populated during training, consumed by the prediction endpoint
var metadata = new TicketModelMetadata
{
    ModelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "model.zip")
};
builder.Services.AddSingleton(metadata);

// Train the model at startup (runs before the app accepts requests)
builder.Services.AddHostedService<ModelTrainerService>();

// Thread-safe prediction engine pool (reloads automatically if model.zip changes)
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelName: "TicketClassifier", filePath: metadata.ModelPath, watchForChanges: true);

builder.Services.AddControllers();

var app = builder.Build();
app.MapControllers();
app.Run();

